# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Optional

def connect_to_db(database):
    conn = sqlite3.connect(database)
    return conn

def check_permission(user, file, permission_type, cursor):
    query = f"SELECT {permission_type} FROM Permissions WHERE UserID={user} AND FilePath='{file}'"
    cursor.execute(query)
    result = cursor.fetchone()
    
    if result:  # Checking if there is any result from the database query
        return True
    else:
        return False
        
def read_file(user, file):
    conn = connect_to_db("DocumentManagementSystem.db")  
    cursor = conn.cursor()
    
    read_permission = check_permission(user, file, "Read", cursor)

    if read_permission:  # Checking if user has the 'read' permission for the given file
        with open(file, 'r') as f:
            return f.read()  
    else:
        raise PermissionError("User does not have permission to read this file.")